/**
 * Generates a password reset token along with its hashed version for secure storage.
 * The plain token is sent to the user, while the hashed version is stored in the database.
 * @param {number} [length=32] - The number of random bytes to generate.
 * @param {number} [expiresInMinutes=60] - Token expiration time in minutes.
 * @returns {Promise<Object>} An object containing the plain token, hashed token, and expiration date.
 */
async function generatePasswordResetData(length = 32, expiresInMinutes = 60) {
  const token = await generatePasswordResetToken(length);

  // Hash the token using SHA-256 for secure database storage
  const hashedToken = crypto
    .createHash('sha256')
    .update(token)
    .digest('hex');

  // Calculate expiration date
  const expiresAt = new Date(Date.now() + expiresInMinutes * 60 * 1000);

  return {
    plainToken: token,        // Send this to the user via email
    hashedToken: hashedToken,  // Store this in the database
    expiresAt: expiresAt       // Store this in the database
  };
}

/**
 * Verifies a plain token against a stored hashed token.
 * @param {string} plainToken - The token received from the user.
 * @param {string} storedHashedToken - The hashed token stored in the database.
 * @param {Date} expiresAt - The expiration date of the token.
 * @returns {boolean} Whether the token is valid and not expired.
 */
function verifyPasswordResetToken(plainToken, storedHashedToken, expiresAt) {
  // Check if token has expired
  if (new Date() > new Date(expiresAt)) {
    return false;
  }

  // Hash the provided token and compare with stored hash
  const hashedToken = crypto
    .createHash('sha256')
    .update(plainToken)
    .digest('hex');

  // Use timing-safe comparison to prevent timing attacks
  try {
    return crypto.timingSafeEqual(
      Buffer.from(hashedToken, 'hex'),
      Buffer.from(storedHashedToken, 'hex')
    );
  } catch (err) {
    return false;
  }
}

